python3 -c "
import json
d=json.load(open('/tmp/trivy-report.json'))
agg={}
for r in d.get('Results',[]):
    for v in r.get('Vulnerabilities',[]) or []:
        k=(v['PkgName'], v.get('InstalledVersion'))
        e=agg.setdefault(k, {'cves':{}, 'fixed':set()})
        e['cves'][v['VulnerabilityID']]=v.get('Severity')
        if v.get('FixedVersion'): 
            for fv in v['FixedVersion'].split(','): e['fixed'].add(fv.strip())
for (pkg,ver),e in sorted(agg.items()):
    fixed=', '.join(sorted(e['fixed'])) or 'NONE'
    cves=', '.join(f'{c}({s[:4]})' for c,s in e['cves'].items())
    print(f'{pkg} @ {ver}')
    print(f'   fixed: {fixed}')
    print(f'   cves: {cves}')
"
